import type { WithRef } from '@andes/common';
import type { FunctionComponent, InputHTMLAttributes, ReactNode } from 'react';

type CheckboxSpecificProps<
  R extends HTMLDivElement | HTMLLabelElement = HTMLDivElement,
> = WithRef<R> & {
  /**
   * Whether the checkbox should be checked or not (controlled behaviour).
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/checkbox#props | Documentation}
   */
  checked?: boolean;

  /**
   * Custom class.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/checkbox#props | Documentation}
   */
  className?: string;

  /**
   * Whether the checkbox should be checked by default (uncontrolled behaviour).
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/checkbox#props | Documentation}
   */
  defaultChecked?: boolean;

  /**
   * Whether the checkbox should be disabled.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/checkbox#props | Documentation}
   * @default false
   */
  disabled?: boolean;

  /**
   * Whether the Checkbox should have an error.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/checkbox#props | Documentation}
   * @default false
   */
  error?: boolean;

  /**
   * Whether the checkbox should appear as highlight when selected.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/checkbox#props | Documentation}
   * @default false
   */
  highlight?: boolean;

  /**
   * Unique identifier.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/checkbox#props | Documentation}
   */
  id?: string;

  /**
   * Whether the checkbox should appear as indeterminate when selected.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/checkbox#props | Documentation}
   * @default false
   */
  indeterminate?: boolean;

  /**
   * Attributes applied to the input element.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/checkbox#props | Documentation}
   */
  inputProps?: InputHTMLAttributes<HTMLInputElement>;

  /**
   * Text to display next to the checkbox.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/checkbox#props | Documentation}
   */
  label?: ReactNode;

  /**
   * Checkbox label position.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/checkbox#props | Documentation}
   * @default 'right'
   */
  labelPosition?: 'left' | 'right';

  /**
   * Function to execute when `change` event triggers.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/checkbox#props | Documentation}
   */
  onChange?: InputHTMLAttributes<HTMLInputElement>['onChange'];

  /**
   * Label that describes the Checkbox functionality for screen readers.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/checkbox#props | Documentation}
   */
  srLabel?: string;
};

type CheckboxProps<
  R extends HTMLDivElement | HTMLLabelElement = HTMLDivElement,
> = CheckboxSpecificProps<R> & Record<string, unknown>; // Leave open props for native element props

/**
 * Checkbox is an interactive component that allows the user to make multiple selections in an options list.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/checkbox | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/55aacd-checkbox/b/657b41 | UI Specs}
 * @example
 * import { Checkbox } from '@andes/checkbox';
 *
 * <Checkbox label="Checkbox label" defaultChecked />
 */
export const Checkbox: FunctionComponent<
  CheckboxProps<HTMLDivElement | HTMLLabelElement>
>;
